var scroll = tree.root.get_node("Main/HUD_Right/VBoxContainer/ChargeScrollContainer")
var panel = scroll.get_node("ChargePanel")
return scroll.size.y - panel.size.y

var panel = tree.root.get_node("Main/HUD_Right/VBoxContainer/ChargeScrollContainer/ChargePanel")
var last_bottom = 0.0
for c in panel.get_children():
	if c is Control and c.visible:
		last_bottom = maxf(last_bottom, c.position.y + c.size.y)
return panel.size.y - last_bottom
